code.C:
#include <stdio.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int a, b;
        scanf("%d %d", &a, &b);
        printf("GCD: %d\n", gcd(a, b));
    }
    return 0;
}

