import sys

def gcd(a, b):
    if b == 0:
        return a
    return gcd(b, a % b)

data = sys.stdin.read().strip().split()
if not data:
    sys.exit()
T = int(data[0])
idx = 1
out = []
for _ in range(T):
    a = int(data[idx]); b = int(data[idx+1]); idx += 2
    out.append(f"GCD: {gcd(a, b)}")
print('\n'.join(out))

